        [...]
        totalWeightsPerEpoch[epochTimestamp] -= weightsPerEpoch[epochTimestamp][state.pool];
+       weightsPerEpoch[epochTimestamp][state.pool] = 0;
        emit GaugeKilled(gauge_);
    }
```


