        if (idxInGen <= 5 || idxInGen >= (maxTokensPerGen - BigInt(5))) {
          console.log(`generation: ${gen} - generationMintCounts: ${count} price minted: ${mintPrice} diff: ${diff}`);
        }
      }

    });

